function sliderReviews() {
    return new Swiper('.architecture .mySwiper', {
        allowTouchMove: false,
        effect: "cube",
        speed: 500,
        cubeEffect: {
            shadow: true,
            slideShadows: true,
            shadowOffset: 20,
            shadowScale: 0.94,
        },
        pagination: {
            el: ".architecture .swiper-pagination",
            clickable: true,
        },
        breakpoints: {
            320: {
                allowTouchMove: true,
            },
            993: {
                allowTouchMove: false,
            }
        }
    });
}

function sliderFormats() {
    var swiper = new Swiper('.formats .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 80,
        speed: 500,
        pagination: {
            el: ".formats .swiper-pagination",
            clickable: true,
        },
        breakpoints: {
            320: {
                slidesPerView: 1,
                spaceBetween: 30,
            },
            577: {
                slidesPerView: 1.5,
                spaceBetween: 40,
            },
            993: {
                slidesPerView: 2,
                spaceBetween: 80,
            }
        }
    })
}

$(document).ready(function () {
    sliderReviews();
    sliderFormats();

    // Header
    const header = document.querySelector('.header');
    const architectureSection = document.querySelector('.architecture');
    if (header && architectureSection) {
        function fixHeader() {
            const headerHeight = header.offsetHeight;
            const wrapper = document.querySelector('.wrapper');
            if (wrapper) {
                wrapper.style.paddingTop = headerHeight + 'px';
            }
        }

        function checkBottomAlign() {
            const rect = architectureSection.getBoundingClientRect();
            const windowBottom = window.innerHeight;

            if (rect.bottom <= windowBottom && rect.bottom >= 0) {
                header.classList.add('header--transform');
            } else {
                header.classList.remove('header--transform');
            }
        }

        window.addEventListener('load', () => {
            fixHeader();
            checkBottomAlign();
        });
        window.addEventListener('resize', fixHeader);
        window.addEventListener('scroll', checkBottomAlign);
    }

    // Tabs
    $(".tab").click(function () {
        let path = $(this).attr("data-tab-path")
        $(this).siblings(".tab").removeClass("tab--active")
        $(this).addClass("tab--active")

        $(this).parents(".tabs-inner").find(".tab__content").removeClass("tab__content--active")
        $(this).parents(".tabs-inner").find(`.tab__content[data-content-path="${path}"]`).addClass("tab__content--active")
    })

    //
    $('.facilities__btn').on('click', function () {

        let tab = $(this).data('tab-path');

        if ($(this).hasClass('active')) {
            $(this).removeClass('active');
            $('tr[data-content-path]').show();
            return;
        }

        $('.facilities__btn').removeClass('active');
        $(this).addClass('active');

        $('tr[data-content-path]').hide();
        $('tr[data-content-path="' + tab + '"]').show();

    });

    // Modal
    $("[data-modal]").click(function () {
        let modalId = $(this).attr("data-modal")

        openModal(modalId)
    })

    function openModal(modalId){
        $(`#${modalId}`).addClass("modal--active")
        $("body").addClass("fixed-body")
    }

    $(".modal").click(function () {
        closeModal()
    })

    $("._close-modal").click(function () {
        closeModal()
    })

    $(".modal__dialog").click(function (e) {
        e.stopPropagation()
    })

    function closeModal() {
        $('.modal--active video').each(function () {
            this.pause();
            this.currentTime = 0;
        });

        $('.modal').removeClass("modal--active")
        $("body").removeClass("fixed-body")
    }

})

