    gsap.context(() => {
        const section = document.querySelector(".formats");
        const wrapper = section.querySelector(".swiper-wrapper");
        const slides = Array.from(wrapper.children);

        function getSlidesPerView() {
            const w = window.innerWidth;
            if (w >= 993) return 2;
            if (w >= 577) return 1.5;
            return 1;
        }

        function getSpaceBetween() {
            const w = window.innerWidth;
            if (w >= 993) return 80;
            if (w >= 577) return 40;
            return 30;
        }

        function getDistance() {
            const slidesPerView = getSlidesPerView();
            const spaceBetween = getSpaceBetween();

            const firstSlides = slides.slice(0, slidesPerView);
            let visibleWidth = 0;
            firstSlides.forEach(slide => visibleWidth += slide.offsetWidth);
            visibleWidth += (slidesPerView - 1) * spaceBetween;

            const totalWidth = slides.reduce((sum, slide) => sum + slide.offsetWidth, 0);
            const totalSpacing = (slides.length - 1) * spaceBetween;

            return -(totalWidth + totalSpacing - visibleWidth);
        }

        gsap.to(wrapper, {
            x: () => getDistance(),
            ease: "none",
            scrollTrigger: {
                trigger: section,
                start: "bottom bottom",
                pin: true,
                scrub: 1,
                end: () => "+=" + Math.abs(getDistance()),
                invalidateOnRefresh: true
            }
        });

        window.addEventListener('resize', () => {
            ScrollTrigger.refresh();
        });

    }, ".formats");
