// Zoom
document.addEventListener('wheel', (e) => {
    if (e.ctrlKey) {
        e.preventDefault();
    }
}, { passive: false });
document.addEventListener('keydown', (e) => {
    if (
        (e.ctrlKey && ['+', '-', '=', '0'].includes(e.key)) ||
        (e.ctrlKey && e.key === 'MouseWheel')
    ) {
        e.preventDefault();
    }
});